SELECT MAX(value) AS max_value_of_interest
FROM alternatives
WHERE alternative_of_interest = 1;

SELECT AVG(value) AS average_value_of_interest
FROM alternatives
WHERE alternative_of_interest IS NOT NULL;

SELECT alternative_id, value
FROM alternatives
WHERE alternative_of_interest = 1;

SELECT alternative_id
FROM alternatives
WHERE rank = (SELECT MAX(rank) FROM alternatives);

SELECT alternative_id, value
FROM alternatives
ORDER BY value DESC;
